import{_ as a,c as i,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Registro de cambios: Historial de versiones | everything-claude-code","description":"Conoce el historial de versiones y los cambios importantes de everything-claude-code. Rastrea nuevas funcionalidades, correcciones de seguridad y actualizaciones de documentación para decidir si necesitas actualizar.","frontmatter":{"title":"Registro de cambios: Historial de versiones | everything-claude-code","sidebarTitle":"Novedades recientes","subtitle":"Registro de cambios: Historial de versiones","description":"Conoce el historial de versiones y los cambios importantes de everything-claude-code. Rastrea nuevas funcionalidades, correcciones de seguridad y actualizaciones de documentación para decidir si necesitas actualizar.","tags":["changelog","updates"],"prerequisite":[],"order":250},"headers":[],"relativePath":"es/affaan-m/everything-claude-code/changelog/release-notes/index.md","filePath":"es/affaan-m/everything-claude-code/changelog/release-notes/index.md"}'),r={name:"es/affaan-m/everything-claude-code/changelog/release-notes/index.md"};function s(t,e,d,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="registro-de-cambios-historial-de-versiones-y-modificaciones" tabindex="-1">Registro de cambios: Historial de versiones y modificaciones <a class="header-anchor" href="#registro-de-cambios-historial-de-versiones-y-modificaciones" aria-label="Permalink to &quot;Registro de cambios: Historial de versiones y modificaciones&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>Conocer los cambios importantes de cada versión</li><li>Rastrear nuevas funcionalidades y correcciones</li><li>Decidir si necesitas actualizar</li></ul><h2 id="historial-de-versiones" tabindex="-1">Historial de versiones <a class="header-anchor" href="#historial-de-versiones" aria-label="Permalink to &quot;Historial de versiones&quot;">​</a></h2><h3 id="_2026-01-24-correcciones-de-seguridad-y-documentacion" tabindex="-1">2026-01-24 - Correcciones de seguridad y documentación <a class="header-anchor" href="#_2026-01-24-correcciones-de-seguridad-y-documentacion" aria-label="Permalink to &quot;2026-01-24 - Correcciones de seguridad y documentación&quot;">​</a></h3><p><strong>Correcciones</strong>:</p><ul><li>🔒 <strong>Corrección de seguridad</strong>: Prevención de vulnerabilidad de inyección de comandos en <code>commandExists()</code><ul><li>Uso de <code>spawnSync</code> en lugar de <code>execSync</code></li><li>Validación de entrada permitiendo solo caracteres alfanuméricos, guiones, guiones bajos y puntos</li></ul></li><li>📝 <strong>Corrección de documentación</strong>: Añadida advertencia de seguridad para <code>runCommand()</code></li><li>🐛 <strong>Corrección de falsos positivos del escáner XSS</strong>: Reemplazo de <code>&lt;script&gt;</code> y <code>&lt;binary&gt;</code> por <code>[script-name]</code> y <code>[binary-name]</code></li><li>📚 <strong>Corrección de documentación</strong>: Corregido <code>npx ts-morph</code> a <code>npx tsx scripts/codemaps/generate.ts</code> en <code>doc-updater.md</code></li></ul><p><strong>Impacto</strong>: #42, #43, #51</p><hr><h3 id="_2026-01-22-soporte-multiplataforma-y-sistema-de-plugins" tabindex="-1">2026-01-22 - Soporte multiplataforma y sistema de plugins <a class="header-anchor" href="#_2026-01-22-soporte-multiplataforma-y-sistema-de-plugins" aria-label="Permalink to &quot;2026-01-22 - Soporte multiplataforma y sistema de plugins&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>🌐 <strong>Soporte multiplataforma</strong>: Todos los hooks y scripts reescritos en Node.js, compatible con Windows, macOS y Linux</li><li>📦 <strong>Empaquetado como plugin</strong>: Distribución como plugin de Claude Code, instalable desde el marketplace</li><li>🎯 <strong>Detección automática del gestor de paquetes</strong>: Soporte para 6 niveles de prioridad de detección <ul><li>Variable de entorno <code>CLAUDE_PACKAGE_MANAGER</code></li><li>Configuración del proyecto <code>.claude/package-manager.json</code></li><li>Campo <code>packageManager</code> en <code>package.json</code></li><li>Detección de archivos lock (package-lock.json, yarn.lock, pnpm-lock.yaml, bun.lockb)</li><li>Configuración global <code>~/.claude/package-manager.json</code></li><li>Fallback al primer gestor de paquetes disponible</li></ul></li></ul><p><strong>Correcciones</strong>:</p><ul><li>🔄 <strong>Carga de hooks</strong>: Carga automática por convención, eliminada la declaración de hooks en <code>plugin.json</code></li><li>📌 <strong>Rutas de hooks</strong>: Uso de <code>${CLAUDE_PLUGIN_ROOT}</code> y rutas relativas</li><li>🎨 <strong>Mejoras de UI</strong>: Añadido gráfico de historial de estrellas y barra de badges</li><li>📖 <strong>Organización de hooks</strong>: Movidos los hooks de session-end de Stop a SessionEnd</li></ul><hr><h3 id="_2026-01-20-mejoras-de-funcionalidad" tabindex="-1">2026-01-20 - Mejoras de funcionalidad <a class="header-anchor" href="#_2026-01-20-mejoras-de-funcionalidad" aria-label="Permalink to &quot;2026-01-20 - Mejoras de funcionalidad&quot;">​</a></h3><p><strong>Nuevas funcionalidades</strong>:</p><ul><li>💾 <strong>Memory Persistence Hooks</strong>: Guardado y carga automática de contexto entre sesiones</li><li>🧠 <strong>Strategic Compact Hook</strong>: Sugerencias inteligentes de compresión de contexto</li><li>📚 <strong>Continuous Learning Skill</strong>: Extracción automática de patrones reutilizables de las sesiones</li><li>🎯 <strong>Strategic Compact Skill</strong>: Estrategias de optimización de tokens</li></ul><hr><h3 id="_2026-01-17-lanzamiento-inicial" tabindex="-1">2026-01-17 - Lanzamiento inicial <a class="header-anchor" href="#_2026-01-17-lanzamiento-inicial" aria-label="Permalink to &quot;2026-01-17 - Lanzamiento inicial&quot;">​</a></h3><p><strong>Funcionalidades iniciales</strong>:</p><ul><li>✨ Colección completa de configuraciones de Claude Code</li><li>🤖 9 agentes especializados</li><li>⚡ 14 comandos slash</li><li>📋 8 conjuntos de reglas</li><li>🔄 Hooks automatizados</li><li>🎨 11 bibliotecas de skills</li><li>🌐 15+ servidores MCP preconfigurados</li><li>📖 Documentación README completa</li></ul><hr><h2 id="convencion-de-nomenclatura-de-versiones" tabindex="-1">Convención de nomenclatura de versiones <a class="header-anchor" href="#convencion-de-nomenclatura-de-versiones" aria-label="Permalink to &quot;Convención de nomenclatura de versiones&quot;">​</a></h2><p>Este proyecto no utiliza versionado semántico tradicional, sino el formato de <strong>versión por fecha</strong> (<code>YYYY-MM-DD</code>).</p><h3 id="tipos-de-version" tabindex="-1">Tipos de versión <a class="header-anchor" href="#tipos-de-version" aria-label="Permalink to &quot;Tipos de versión&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tipo</th><th>Descripción</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>Nueva funcionalidad</strong></td><td>Añade nueva funcionalidad o mejora importante</td><td><code>feat: add new agent</code></td></tr><tr><td><strong>Corrección</strong></td><td>Corrige bugs o problemas</td><td><code>fix: resolve hook loading issue</code></td></tr><tr><td><strong>Documentación</strong></td><td>Actualización de documentación</td><td><code>docs: update README</code></td></tr><tr><td><strong>Estilo</strong></td><td>Formato o estilo de código</td><td><code>style: fix indentation</code></td></tr><tr><td><strong>Refactorización</strong></td><td>Refactorización de código</td><td><code>refactor: simplify hook logic</code></td></tr><tr><td><strong>Rendimiento</strong></td><td>Optimización de rendimiento</td><td><code>perf: improve context loading</code></td></tr><tr><td><strong>Pruebas</strong></td><td>Relacionado con pruebas</td><td><code>test: add unit tests</code></td></tr><tr><td><strong>Build</strong></td><td>Sistema de build o dependencias</td><td><code>build: update package.json</code></td></tr><tr><td><strong>Revertir</strong></td><td>Revierte un commit anterior</td><td><code>revert: remove version field</code></td></tr></tbody></table><hr><h2 id="como-obtener-actualizaciones" tabindex="-1">Cómo obtener actualizaciones <a class="header-anchor" href="#como-obtener-actualizaciones" aria-label="Permalink to &quot;Cómo obtener actualizaciones&quot;">​</a></h2><h3 id="actualizacion-desde-el-marketplace-de-plugins" tabindex="-1">Actualización desde el marketplace de plugins <a class="header-anchor" href="#actualizacion-desde-el-marketplace-de-plugins" aria-label="Permalink to &quot;Actualización desde el marketplace de plugins&quot;">​</a></h3><p>Si instalaste Everything Claude Code desde el marketplace de plugins:</p><ol><li>Abre Claude Code</li><li>Ejecuta <code>/plugin update everything-claude-code</code></li><li>Espera a que se complete la actualización</li></ol><h3 id="actualizacion-manual" tabindex="-1">Actualización manual <a class="header-anchor" href="#actualizacion-manual" aria-label="Permalink to &quot;Actualización manual&quot;">​</a></h3><p>Si clonaste el repositorio manualmente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/everything-claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="instalacion-desde-el-marketplace" tabindex="-1">Instalación desde el marketplace <a class="header-anchor" href="#instalacion-desde-el-marketplace" aria-label="Permalink to &quot;Instalación desde el marketplace&quot;">​</a></h3><p>Primera instalación:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> affaan-m/everything-claude-code</span></span></code></pre></div><hr><h2 id="analisis-de-impacto-de-cambios" tabindex="-1">Análisis de impacto de cambios <a class="header-anchor" href="#analisis-de-impacto-de-cambios" aria-label="Permalink to &quot;Análisis de impacto de cambios&quot;">​</a></h2><h3 id="correcciones-de-seguridad-actualizacion-obligatoria" tabindex="-1">Correcciones de seguridad (actualización obligatoria) <a class="header-anchor" href="#correcciones-de-seguridad-actualizacion-obligatoria" aria-label="Permalink to &quot;Correcciones de seguridad (actualización obligatoria)&quot;">​</a></h3><ul><li><strong>2026-01-24</strong>: Corrección de vulnerabilidad de inyección de comandos, se recomienda encarecidamente actualizar</li></ul><h3 id="mejoras-de-funcionalidad-actualizacion-opcional" tabindex="-1">Mejoras de funcionalidad (actualización opcional) <a class="header-anchor" href="#mejoras-de-funcionalidad-actualizacion-opcional" aria-label="Permalink to &quot;Mejoras de funcionalidad (actualización opcional)&quot;">​</a></h3><ul><li><strong>2026-01-22</strong>: Soporte multiplataforma, usuarios de Windows deben actualizar</li><li><strong>2026-01-20</strong>: Nuevas mejoras de funcionalidad, actualizar según necesidad</li></ul><h3 id="actualizaciones-de-documentacion-no-requiere-actualizacion" tabindex="-1">Actualizaciones de documentación (no requiere actualización) <a class="header-anchor" href="#actualizaciones-de-documentacion-no-requiere-actualizacion" aria-label="Permalink to &quot;Actualizaciones de documentación (no requiere actualización)&quot;">​</a></h3><ul><li>Las actualizaciones de documentación no afectan la funcionalidad, puedes consultar el README manualmente</li></ul><hr><h2 id="problemas-conocidos" tabindex="-1">Problemas conocidos <a class="header-anchor" href="#problemas-conocidos" aria-label="Permalink to &quot;Problemas conocidos&quot;">​</a></h2><h3 id="version-actual-2026-01-24" tabindex="-1">Versión actual (2026-01-24) <a class="header-anchor" href="#version-actual-2026-01-24" aria-label="Permalink to &quot;Versión actual (2026-01-24)&quot;">​</a></h3><ul><li>Sin problemas graves conocidos</li></ul><h3 id="versiones-anteriores" tabindex="-1">Versiones anteriores <a class="header-anchor" href="#versiones-anteriores" aria-label="Permalink to &quot;Versiones anteriores&quot;">​</a></h3><ul><li>Antes de 2026-01-22: La carga de hooks requería configuración manual (corregido en 2026-01-22)</li><li>Antes de 2026-01-20: Sin soporte para Windows (corregido en 2026-01-22)</li></ul><hr><h2 id="contribuciones-y-feedback" tabindex="-1">Contribuciones y feedback <a class="header-anchor" href="#contribuciones-y-feedback" aria-label="Permalink to &quot;Contribuciones y feedback&quot;">​</a></h2><h3 id="reportar-problemas" tabindex="-1">Reportar problemas <a class="header-anchor" href="#reportar-problemas" aria-label="Permalink to &quot;Reportar problemas&quot;">​</a></h3><p>Si encuentras un bug o tienes sugerencias de funcionalidad:</p><ol><li>Busca en <a href="https://github.com/affaan-m/everything-claude-code/issues" target="_blank" rel="noreferrer">GitHub Issues</a> si ya existe un problema similar</li><li>Si no existe, crea un nuevo Issue proporcionando: <ul><li>Información de versión</li><li>Sistema operativo</li><li>Pasos para reproducir</li><li>Comportamiento esperado vs comportamiento real</li></ul></li></ol><h3 id="enviar-pr" tabindex="-1">Enviar PR <a class="header-anchor" href="#enviar-pr" aria-label="Permalink to &quot;Enviar PR&quot;">​</a></h3><p>¡Las contribuciones son bienvenidas! Consulta <a href="https://github.com/affaan-m/everything-claude-code/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> para más detalles.</p><hr><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><ul><li>Everything Claude Code utiliza números de versión por fecha (<code>YYYY-MM-DD</code>)</li><li>Las correcciones de seguridad (como 2026-01-24) requieren actualización obligatoria</li><li>Las mejoras de funcionalidad se pueden actualizar según necesidad</li><li>Los usuarios del marketplace de plugins usan <code>/plugin update</code> para actualizar</li><li>Los usuarios con instalación manual usan <code>git pull</code> para actualizar</li><li>Para reportar problemas y enviar PRs, sigue las guías del proyecto</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos sobre <strong><a href="./../../appendix/config-reference/">Referencia de archivos de configuración</a></strong>.</p><p>Aprenderás:</p><ul><li>Descripción completa de los campos de <code>settings.json</code></li><li>Opciones avanzadas de configuración de hooks</li><li>Detalles de configuración de servidores MCP</li><li>Mejores prácticas para configuraciones personalizadas</li></ul></blockquote>',64)])])}const m=a(r,[["render",s]]);export{h as __pageData,m as default};
